class Solution:
    def maximumValueSum(self, nums, k, edges):
        gains = sorted([(x ^ k) - x for x in nums], reverse=True)
        total = sum(nums)
        i = 0
        while i + 1 < len(gains) and gains[i] + gains[i+1] > 0:
            total += gains[i] + gains[i+1]
            i += 2
        return total

