var maximumValueSum = function(nums, k, edges) {
    const gains = nums.map(x => (x ^ k) - x).sort((a, b) => b - a);
    let total = nums.reduce((s, x) => s + x, 0);
    for (let i = 0; i + 1 < gains.length; i += 2) {
        if (gains[i] + gains[i+1] > 0) total += gains[i] + gains[i+1];
        else break;
    }
    return total;
};
